SELECT model_name, max_payload, reach
FROM robot_models
WHERE max_payload > 5.0;

SELECT arm_name, installation_date
FROM robot_arms
WHERE status = 'active';

SELECT COUNT(*) AS active_arms_count
FROM robot_arms
WHERE status = 'active';

SELECT task_name
FROM robot_tasks
WHERE task_id = 0;

SELECT COUNT(*) AS shoulder_angle_count
FROM kinematic_data
WHERE shoulder > 60;

SELECT waist
FROM kinematic_data
WHERE data_quality = 'good';

SELECT COUNT(*) AS task_count
FROM robot_tasks
WHERE task_name = 'Inspection';

SELECT task_name, COUNT(*) AS task_count
FROM robot_tasks
GROUP BY task_name;

SELECT arm_id, COUNT(*) AS total_tasks
FROM tasks_performed
GROUP BY arm_id;

SELECT task_name, priority
FROM robot_tasks
WHERE priority > 1;
